      <div class="status sold-out">SOLD OUT</div>
    </div>

    <div class="edition" data-edition="black" data-state="coming-soon">
      <canvas class="edition-canvas"></canvas>
      <h3>Obsidian Strike</h3>
      <div class="price">Black nickel · run of 250</div>
      <div class="status coming-soon">Minting Next Season — Winter 2026</div>
    </div>

  </div>
</section>

<footer>
  &copy; 2024–2026 WastedToken Mint. Every die retired after its run. No reprints.
</footer>

<script>
(function(){
  "use strict";

  // ---------- shared coin math (pure functions of t / fixed angles) ----------

  function computeAngles(t){
    var spinY = t * Math.PI * 2;       // rotation about the vertical axis, one full turn per loop
    var flipX = t * Math.PI * 4;       // flip about the horizontal axis, two flips per loop
    var cosY = Math.cos(spinY), cosX = Math.cos(flipX);
    return {
      spinY: spinY,
      flipX: flipX,
      widthScale: Math.abs(cosY),
      heightScale: Math.abs(cosX),
      showFront: (cosY * cosX) >= 0
    };
  }

  var METALS = {
    heroGold:  { light:'#fdf1c0', base:'#caa43d', dark:'#5b430e', rim:'#8a681c', ink:'#3c2a08' },
    bronze:    { light:'#e6b784', base:'#8a5a2b', dark:'#3a2210', rim:'#6b431d', ink:'#2b1608' },
    silver:    { light:'#ffffff', base:'#b9bec4', dark:'#42464b', rim:'#8d9296', ink:'#33363a' },
    gold:      { light:'#fff2b0', base:'#d4af37', dark:'#5c430e', rim:'#a8811f', ink:'#4a3608' },
    black:     { light:'#8fe6ff', base:'#1c1c22', dark:'#000000', rim:'#101014', ink:'#cfeeff' }
  };

  function drawArcText(ctx, text, radius, centerAngle, spanAngle, color, flip, sizeFactor){
    var n = text.length;
    if(n === 0) return;
    var angleStep = n > 1 ? spanAngle / (n - 1) : 0;
    var a = centerAngle - (spanAngle / 2);
    ctx.save();
    ctx.fillStyle = color;
    ctx.font = 'bold ' + Math.round(radius * (sizeFactor || 0.13)) + 'px Arial, sans-serif';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    for(var i = 0; i < n; i++){
      var x = Math.cos(a) * radius, y = Math.sin(a) * radius;
      ctx.save();
      ctx.translate(x, y);
      ctx.rotate(a + Math.PI/2 + (flip ? Math.PI : 0));
      ctx.fillText(text[i], 0, 0);
      ctx.restore();
      a += angleStep;
    }
    ctx.restore();
  }

  function drawFrontEmblem(ctx, R, metal){
    ctx.save();
    ctx.strokeStyle = metal.ink;
    ctx.lineWidth = R * 0.035;
    ctx.beginPath(); ctx.arc(0,0,R*0.86,0,Math.PI*2); ctx.stroke();
    ctx.lineWidth = R * 0.012;
    ctx.beginPath(); ctx.arc(0,0,R*0.78,0,Math.PI*2); ctx.stroke();

    drawArcText(ctx, 'WASTEDTOKEN MINT', R*0.92, -Math.PI/2, Math.PI*0.95, metal.ink, false, 0.115);
    drawArcText(ctx, '\u2022 EST 2024 \u2022', R*0.92, Math.PI/2, Math.PI*0.6, metal.ink, true, 0.11);

    ctx.font = 'bold ' + Math.round(R*0.95) + 'px Georgia, serif';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';

    ctx.save(); ctx.translate(R*0.035, R*0.06); ctx.fillStyle='rgba(0,0,0,0.45)'; ctx.fillText('W',0,0); ctx.restore();
    ctx.save(); ctx.translate(-R*0.035, -R*0.05); ctx.fillStyle='rgba(255,255,255,0.5)'; ctx.fillText('W',0,0); ctx.restore();
    ctx.fillStyle = metal.ink;
    ctx.fillText('W',0,0.02*R);

    ctx.restore();
  }

  function drawBackFace(ctx, R, metal, label){
    ctx.save();
    ctx.strokeStyle = metal.ink;
    ctx.lineWidth = R * 0.035;
    ctx.beginPath(); ctx.arc(0,0,R*0.86,0,Math.PI*2); ctx.stroke();
    ctx.lineWidth = R * 0.012;
    ctx.beginPath(); ctx.arc(0,0,R*0.78,0,Math.PI*2); ctx.stroke();

    drawArcText(ctx, 'WASTEDTOKEN MINT', R*0.92, -Math.PI/2, Math.PI*0.95, metal.ink, false, 0.115);
    drawArcText(ctx, '\u2022 LIMITED EDITION \u2022', R*0.92, Math.PI/2, Math.PI*0.75, metal.ink, true, 0.1);

    var parts = label.split(' ');
    var top = parts[0];
    var rest = parts.slice(1).join(' ');

    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.font = 'bold ' + Math.round(R*0.46) + 'px Georgia, serif';
    ctx.save(); ctx.translate(R*0.03, R*0.05); ctx.fillStyle='rgba(0,0,0,0.4)'; ctx.fillText(top,0,-R*0.1); ctx.restore();
    ctx.save(); ctx.translate(-R*0.03, -R*0.04); ctx.fillStyle='rgba(255,255,255,0.45)'; ctx.fillText(top,0,-R*0.1); ctx.restore();
    ctx.fillStyle = metal.ink;
    ctx.fillText(top, 0, -R*0.1);

    ctx.font = 'bold ' + Math.round(R*0.2) + 'px Arial, sans-serif';
    ctx.fillStyle = metal.ink;
    ctx.fillText(rest, 0, R*0.26);

    ctx.restore();
  }

  function drawCoin(ctx, o){
    var cx=o.cx, cy=o.cy, R=o.baseR;
    var wS=o.widthScale, hS=o.heightScale;
    var edgeThk = R * 0.16;

    ctx.save();
    ctx.translate(cx, cy);
    ctx.scale(Math.max(wS,0.035), Math.max(hS,0.035));

    // ----- rim / edge (with reeded ridges) -----
    ctx.save();
    ctx.beginPath();
    ctx.arc(0,0,R+edgeThk,0,Math.PI*2);
    ctx.closePath();
    var rimGrad = ctx.createRadialGradient(-R*0.3,-R*0.3,R*0.15, 0,0, R+edgeThk);
    rimGrad.addColorStop(0, o.metal.light);
    rimGrad.addColorStop(0.55, o.metal.rim);
    rimGrad.addColorStop(1, o.metal.dark);
    ctx.fillStyle = rimGrad;
    ctx.fill();

    var nTicks = 96;
    for(var i=0;i<nTicks;i++){
      var a = (i/nTicks) * Math.PI * 2;
      var ca = Math.cos(a), sa = Math.sin(a);
      var x1 = ca*R*0.98, y1 = sa*R*0.98;
      var x2 = ca*(R+edgeThk), y2 = sa*(R+edgeThk);
      ctx.strokeStyle = (i % 2 === 0) ? 'rgba(255,255,255,0.32)' : 'rgba(0,0,0,0.38)';
      ctx.lineWidth = R * 0.022;
      ctx.beginPath(); ctx.moveTo(x1,y1); ctx.lineTo(x2,y2); ctx.stroke();
    }
    ctx.restore();

    // ----- face -----
    ctx.save();
    ctx.beginPath();
    ctx.arc(0,0,R,0,Math.PI*2);
    ctx.closePath();
    ctx.clip();

    var faceGrad = ctx.createRadialGradient(-R*0.35,-R*0.35,R*0.1, 0,0, R*1.15);
    faceGrad.addColorStop(0, o.metal.light);
    faceGrad.addColorStop(0.55, o.metal.base);
    faceGrad.addColorStop(1, o.metal.dark);
    ctx.fillStyle = faceGrad;
    ctx.fillRect(-R*1.3,-R*1.3, R*2.6, R*2.6);

    if(o.showFront){
      drawFrontEmblem(ctx, R, o.metal);
    } else {
      drawBackFace(ctx, R, o.metal, o.backLabel || '10,000 TOKENS');
    }

    // ----- moving specular highlight -----
    var hx = Math.sin(o.spinY) * R * 0.6;
    var hy = Math.sin(o.flipX) * R * 0.6;
    var hl = ctx.createRadialGradient(hx,hy,0, hx,hy, R*0.95);
    hl.addColorStop(0, 'rgba(255,255,255,0.9)');
    hl.addColorStop(0.35, 'rgba(255,255,255,0.28)');
    hl.addColorStop(1, 'rgba(255,255,255,0)');
    ctx.globalCompositeOperation = 'lighter';
    ctx.fillStyle = hl;
    ctx.fillRect(-R*1.3,-R*1.3, R*2.6, R*2.6);
    ctx.globalCompositeOperation = 'source-over';

    ctx.restore(); // face clip
    ctx.restore(); // scale/translate
  }

  // ---------- hero canvas ----------

  var heroCanvas = document.getElementById('coin-hero');
  var heroCtx = heroCanvas.getContext('2d');
  var HW = heroCanvas.width, HH = heroCanvas.height;
  var heroCx = HW/2, heroCy = HH/2;
  var heroR = Math.min(HW,HH) * 0.30; // generous margin, never touches edges

  function renderHero(t){
    heroCtx.clearRect(0,0,HW,HH);

    // simple backdrop so only the coin reads as subject
    var bg = heroCtx.createRadialGradient(heroCx, heroCy*0.85, heroR*0.4, heroCx, heroCy, HW*0.75);
    bg.addColorStop(0, '#1b1a17');
    bg.addColorStop(1, '#0b0b0f');
    heroCtx.fillStyle = bg;
    heroCtx.fillRect(0,0,HW,HH);

    var ang = computeAngles(t);

    drawCoin(heroCtx, {
      cx: heroCx, cy: heroCy, baseR: heroR,
      widthScale: ang.widthScale, heightScale: ang.heightScale,
      showFront: ang.showFront,
      spinY: ang.spinY, flipX: ang.flipX,
      metal: METALS.heroGold,
      backLabel: '10,000 TOKENS'
    });
  }

  var playing = true;
  var rafId = null;
  var startTs = null;
  var LOOP_MS = 6000;

  function frame(now){
    if(!playing) return;
    if(startTs === null) startTs = now;
    var t = ((now - startTs) % LOOP_MS) / LOOP_MS;
    renderHero(t);
    rafId = requestAnimationFrame(frame);
  }

  rafId = requestAnimationFrame(frame);

  window.demo = {
    canvas: heroCanvas,
    setTime: function(t){
      playing = false;
      if(rafId !== null){ cancelAnimationFrame(rafId); rafId = null; }
      var tt = ((t % 1) + 1) % 1;
      renderHero(tt);
    },
    pause: function(){
      playing = false;
      if(rafId !== null){ cancelAnimationFrame(rafId); rafId = null; }
    }
  };

  // ---------- edition tiles (static procedural renders) ----------

  function renderEdition(canvas, metalKey, state, seasonLabel){
    var dpr = 1;
    var size = 260;
    canvas.width = size; canvas.height = size;
    var ctx = canvas.getContext('2d');
    var w = size, h = size;

    var bg = ctx.createLinearGradient(0,0,0,h);
    bg.addColorStop(0, '#17161a');
    bg.addColorStop(1, '#0e0e12');
    ctx.fillStyle = bg;
    ctx.fillRect(0,0,w,h);

    var cx = w/2, cy = h/2;
    var baseR = Math.min(w,h) * 0.30;

    drawCoin(ctx, {
      cx: cx, cy: cy, baseR: baseR,
      widthScale: 0.90, heightScale: 0.985,
      showFront: true,
      spinY: 0.46, flipX: 0.17,
      metal: METALS[metalKey],
      backLabel: '10,000 TOKENS'
    });

    if(state === 'sold-out'){
      ctx.save();
      ctx.translate(cx, cy);
      ctx.rotate(-0.22);
      ctx.fillStyle = 'rgba(170,20,20,0.88)';
      ctx.fillRect(-baseR*1.35, -baseR*0.22, baseR*2.7, baseR*0.44);
      ctx.strokeStyle = 'rgba(255,255,255,0.9)';
      ctx.lineWidth = 2;
      ctx.strokeRect(-baseR*1.35, -baseR*0.22, baseR*2.7, baseR*0.44);
      ctx.fillStyle = '#fff';
      ctx.font = 'bold ' + Math.round(baseR*0.28) + 'px Arial, sans-serif';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText('SOLD OUT', 0, 2);
      ctx.restore();
    } else if(state === 'coming-soon'){
      ctx.save();
      ctx.fillStyle = 'rgba(0,0,0,0.55)';
      ctx.fillRect(0, h - h*0.24, w, h*0.24);
      ctx.fillStyle = '#8fe6ff';
      ctx.font = 'bold ' + Math.round(baseR*0.155) + 'px Arial, sans-serif';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText(seasonLabel.toUpperCase(), w/2, h - h*0.12);
      ctx.restore();
    }
  }

  var tiles = document.querySelectorAll('.edition');
  tiles.forEach(function(tile){
    var edition = tile.getAttribute('data-edition');
    var state = tile.getAttribute('data-state');
    var canvas = tile.querySelector('.edition-canvas');
    var metalKey = edition === 'black' ? 'black' : edition;
    renderEdition(canvas, metalKey, state, 'Minting Next Season \u2014 Winter 2026');
  });

})();
</script>

</body>
</html>
